export const LCE_SCHEMA_VERSION = '1.1.1';

export function normalizeSymbol(symbol){ return String(symbol || '').replace('-USD','').replace('USDT','').replace('PERP','').toUpperCase().trim(); }
export function num(v, fallback=0){ const n = Number(v); return Number.isFinite(n) ? n : fallback; }
export function toMs(v){ if(v instanceof Date) return v.getTime(); if(typeof v === 'number') return v < 1e10 ? v * 1000 : v; const p = Date.parse(v); return Number.isFinite(p) ? p : Date.now(); }
export function normalizeCandle(c){ const t = toMs(c.time ?? c.timeMs ?? c.t ?? c.ts); return { time:t, timeMs:t, open:num(c.open ?? c.o), high:num(c.high ?? c.h), low:num(c.low ?? c.l), close:num(c.close ?? c.c), volume:num(c.volume ?? c.v,0) }; }
export function normalizeCandles(candles=[]){ return candles.map(normalizeCandle).filter(c => c.high >= c.low && c.high > 0 && c.low > 0).sort((a,b)=>a.timeMs-b.timeMs); }
export function normalizeBookLevel(x){ if(Array.isArray(x)) return { price:num(x[0]), size:num(x[1]) }; return { price:num(x.price ?? x.px), size:num(x.size ?? x.sz ?? x.qty) }; }
export function normalizeOrderBook(book={}){ return { timeMs:toMs(book.time ?? book.timeMs ?? book.ts), bids:(book.bids||[]).map(normalizeBookLevel).filter(x=>x.price>0&&x.size>0).sort((a,b)=>b.price-a.price), asks:(book.asks||[]).map(normalizeBookLevel).filter(x=>x.price>0&&x.size>0).sort((a,b)=>a.price-b.price) }; }
export function normalizeTrade(t={}){ const raw = String(t.side ?? t.direction ?? '').toLowerCase(); const side = raw.includes('buy') || raw === 'b' ? 'buy' : raw.includes('sell') || raw === 's' ? 'sell' : 'unknown'; return { timeMs:toMs(t.time ?? t.timeMs ?? t.ts), price:num(t.price ?? t.px), size:num(t.size ?? t.sz ?? t.qty,0), side }; }
export function normalizeTrades(trades=[]){ return trades.map(normalizeTrade).filter(t=>t.price>0&&t.size>=0).sort((a,b)=>a.timeMs-b.timeMs); }
export function timeframeMs(tf){ const n = Number(String(tf).slice(0,-1)); const u = String(tf).slice(-1); if(!Number.isFinite(n)) return 60000; return u==='m'?n*60000:u==='h'?n*3600000:u==='d'?n*86400000:u==='w'?n*604800000:u==='M'?n*2592000000:60000; }
export function aggregateCandles(candles, timeframe, max=1000){ const span=timeframeMs(timeframe), m=new Map(); for(const c of normalizeCandles(candles)){ const k=Math.floor(c.timeMs/span)*span; const e=m.get(k); if(!e)m.set(k,{time:k,timeMs:k,open:c.open,high:c.high,low:c.low,close:c.close,volume:c.volume}); else {e.high=Math.max(e.high,c.high); e.low=Math.min(e.low,c.low); e.close=c.close; e.volume+=c.volume;} } return [...m.values()].sort((a,b)=>a.timeMs-b.timeMs).slice(-max); }

function level({symbol,timeframe,side,price,strength,source,widthBps=10}){ const w=Math.max(price*widthBps/10000,1e-9); return {symbol,timeframe,side,price,zoneLow:price-w,zoneHigh:price+w,strength:Math.max(0,Math.min(100,strength)),source,sources:[source],timeMs:Date.now()}; }
export function detectCandleLevels({symbol,timeframe,candles}){ const c=normalizeCandles(candles); if(c.length<10) return []; const out=[]; const win=c.slice(-Math.min(c.length,120)); const hi=Math.max(...win.map(x=>x.high)); const lo=Math.min(...win.map(x=>x.low)); out.push(level({symbol,timeframe,side:'supply',price:hi,strength:62,source:'range-high-liquidity'})); out.push(level({symbol,timeframe,side:'demand',price:lo,strength:62,source:'range-low-liquidity'})); for(let i=3;i<c.length-3;i++){ const cur=c[i], left=c.slice(i-3,i), right=c.slice(i+1,i+4); if(left.every(x=>cur.high>=x.high)&&right.every(x=>cur.high>x.high)) out.push(level({symbol,timeframe,side:'supply',price:cur.high,strength:67,source:'swing-pivot-high'})); if(left.every(x=>cur.low<=x.low)&&right.every(x=>cur.low<x.low)) out.push(level({symbol,timeframe,side:'demand',price:cur.low,strength:67,source:'swing-pivot-low'})); } return out.slice(-80); }
export function detectOrderBookLevels({symbol,timeframe='live',book}){ const b=normalizeOrderBook(book); const out=[]; for(const [arr,side,source] of [[b.bids,'demand','orderbook-bid-wall'],[b.asks,'supply','orderbook-ask-wall']]){ const top=[...arr].sort((a,b)=>b.size-a.size).slice(0,3); for(const x of top) out.push(level({symbol,timeframe,side,price:x.price,strength:70,source,widthBps:5})); } return out; }
export function detectTradeLevels({symbol,timeframe='live',trades}){ const t=normalizeTrades(trades); if(!t.length) return []; const total=t.reduce((a,x)=>a+x.size,0)||1; const vwap=t.reduce((a,x)=>a+x.price*x.size,0)/total; const buy=t.filter(x=>x.side==='buy').reduce((a,x)=>a+x.size,0); const sell=t.filter(x=>x.side==='sell').reduce((a,x)=>a+x.size,0); return [level({symbol,timeframe,side:buy>=sell?'demand':'supply',price:vwap,strength:65,source:'trade-vwap-pressure',widthBps:7})]; }
export function buildConfluenceZones({symbol,levels,clusterToleranceBps=18}){ const clusters=[]; for(const l of [...levels].filter(x=>x&&x.price>0).sort((a,b)=>a.price-b.price)){ let c=clusters.find(z=>Math.abs(l.price-z.price)/z.price*10000<=clusterToleranceBps && (l.side===z.side||l.side==='neutral'||z.side==='neutral')); if(!c){ clusters.push({symbol,side:l.side,price:l.price,zoneLow:l.zoneLow,zoneHigh:l.zoneHigh,levels:[l],sources:[...new Set(l.sources||[l.source])],strength:l.strength}); } else { c.levels.push(l); c.price=c.levels.reduce((a,x)=>a+x.price,0)/c.levels.length; c.zoneLow=Math.min(c.zoneLow,l.zoneLow); c.zoneHigh=Math.max(c.zoneHigh,l.zoneHigh); c.sources=[...new Set(c.levels.flatMap(x=>x.sources||[x.source]))]; c.strength=Math.min(100,c.levels.reduce((a,x)=>a+x.strength,0)/c.levels.length+c.sources.length*7+c.levels.length*3); } } return clusters.map((c,i)=>({id:`${symbol}:zone:${i}`,symbol,timeframe:[...new Set(c.levels.map(x=>x.timeframe))].join('+'),side:c.side,price:c.price,zoneLow:c.zoneLow,zoneHigh:c.zoneHigh,strength:c.strength,sources:c.sources,sourceCount:c.sources.length,levelCount:c.levels.length,status:c.strength>=75?'strong':c.strength>=55?'watch':'weak',createdAt:new Date().toISOString()})).sort((a,b)=>b.strength-a.strength); }

export class LceEngine{ constructor(config={}){ this.config={symbols:(config.symbols||[]).map(normalizeSymbol),timeframes:config.timeframes||['1m','15m','1h','4h'],maxTrades:config.maxTrades||2000,marketDataOnly:config.marketDataOnly!==false}; this.state=new Map(); for(const s of this.config.symbols) this.state.set(s,{candles:new Map(),book:null,trades:[],levels:[],zones:[]}); } ensure(s){ s=normalizeSymbol(s); if(!this.state.has(s)) this.state.set(s,{candles:new Map(),book:null,trades:[],levels:[],zones:[]}); return [s,this.state.get(s)]; } ingestCandles(s,tf,c){ const [sym,st]=this.ensure(s); const n=normalizeCandles(c); st.candles.set(tf,n); if(tf==='1m') for(const t of this.config.timeframes) if(t!=='1m'&&!st.candles.has(t)) st.candles.set(t,aggregateCandles(n,t)); this.recompute(sym); return this; } ingestOrderBook(s,b){ const [sym,st]=this.ensure(s); st.book=normalizeOrderBook(b); this.recompute(sym); return this; } ingestTrades(s,t){ const [sym,st]=this.ensure(s); st.trades=[...st.trades,...normalizeTrades(t)].slice(-this.config.maxTrades); this.recompute(sym); return this; } recompute(sym){ const st=this.state.get(sym); const levels=[]; for(const [tf,c] of st.candles) levels.push(...detectCandleLevels({symbol:sym,timeframe:tf,candles:c})); if(st.book) levels.push(...detectOrderBookLevels({symbol:sym,book:st.book})); if(st.trades.length) levels.push(...detectTradeLevels({symbol:sym,trades:st.trades})); st.levels=levels; st.zones=buildConfluenceZones({symbol:sym,levels}); } getLevels(s){ return this.state.get(normalizeSymbol(s))?.levels||[]; } getZones(s){ return this.state.get(normalizeSymbol(s))?.zones||[]; } getStatus(){ return {state:'ready',marketDataOnly:true,symbols:Object.fromEntries([...this.state].map(([s,st])=>[s,{levels:st.levels.length,zones:st.zones.length,hasBook:!!st.book,trades:st.trades.length,candleSets:[...st.candles.keys()]}]))}; } }
export function createLceEngine(config={}){ return new LceEngine(config); }
